/**
 * AI Support Platform — embeddable chat widget loader.
 *
 * Usage (pasted by clients before </body> on their own website, generated by
 * POST /api/channels/webchat — see ChannelsController.ConnectWebChat):
 *
 *   <script src="https://platform.example.com/widget-loader.js" data-key="pub_xxx" async></script>
 *
 * This file is plain JS (no build step, no framework) so it loads fast and has
 * zero dependency on the host site's own stack. It creates:
 *   1. A floating chat bubble button, fixed bottom-right
 *   2. An iframe (hidden until clicked) pointing at /widget/chat?key=pub_xxx —
 *      that route renders WidgetPage.tsx, the actual React chat UI, served
 *      from this same origin so it can freely use SignalR/cookies/localStorage
 *      without the host page's CSP getting in the way.
 *
 * Sprint 6 hardening note: per-company origin allowlisting for embed validation
 * is intentionally deferred — see Program.cs WidgetCors policy comment.
 */
(function () {
  'use strict';

  var currentScript = document.currentScript;
  if (!currentScript) return;

  var publicKey = currentScript.getAttribute('data-key');
  if (!publicKey) {
    console.error('[AI Support Widget] Missing data-key attribute on the embed script tag.');
    return;
  }

  // Derive the platform origin from the script's own src — works in dev
  // (http://localhost:5173/widget-loader.js) and prod alike without hardcoding.
  var scriptUrl = new URL(currentScript.src);
  var platformOrigin = scriptUrl.origin;

  var isOpen = false;

  function injectStyles() {
    var style = document.createElement('style');
    style.textContent =
      '.aisp-bubble{position:fixed;bottom:20px;right:20px;width:56px;height:56px;' +
      'border-radius:9999px;background:#0d9488;border:none;cursor:pointer;' +
      'box-shadow:0 8px 24px rgba(0,0,0,0.25);z-index:2147483646;' +
      'display:flex;align-items:center;justify-content:center;transition:transform 0.15s ease;}' +
      '.aisp-bubble:hover{transform:scale(1.06);}' +
      '.aisp-bubble svg{width:26px;height:26px;}' +
      '.aisp-frame-wrap{position:fixed;bottom:88px;right:20px;width:380px;height:560px;' +
      'max-width:calc(100vw - 40px);max-height:calc(100vh - 120px);border-radius:16px;' +
      'overflow:hidden;box-shadow:0 16px 48px rgba(0,0,0,0.35);z-index:2147483647;' +
      'display:none;background:#0f172a;}' +
      '.aisp-frame-wrap.aisp-open{display:block;}' +
      '.aisp-frame-wrap iframe{width:100%;height:100%;border:none;}' +
      '@media (max-width:480px){.aisp-frame-wrap{right:0;bottom:0;width:100vw;height:100vh;' +
      'max-width:100vw;max-height:100vh;border-radius:0;}}';
    document.head.appendChild(style);
  }

  function createBubble() {
    var button = document.createElement('button');
    button.className = 'aisp-bubble';
    button.setAttribute('aria-label', 'Open chat');
    button.innerHTML =
      '<svg viewBox="0 0 24 24" fill="none" stroke="white" stroke-width="2" ' +
      'stroke-linecap="round" stroke-linejoin="round">' +
      '<path d="M21 11.5a8.38 8.38 0 0 1-.9 3.8 8.5 8.5 0 0 1-7.6 4.7 8.38 8.38 0 0 1-3.8-.9L3 21l1.9-5.7a8.38 8.38 0 0 1-.9-3.8 8.5 8.5 0 0 1 4.7-7.6 8.38 8.38 0 0 1 3.8-.9h.5a8.48 8.48 0 0 1 8 8v.5z"/>' +
      '</svg>';
    button.addEventListener('click', toggleWidget);
    document.body.appendChild(button);
    return button;
  }

  function createFrame() {
    var wrap = document.createElement('div');
    wrap.className = 'aisp-frame-wrap';

    var iframe = document.createElement('iframe');
    iframe.src = platformOrigin + '/widget/chat?key=' + encodeURIComponent(publicKey);
    iframe.title = 'Chat support widget';
    iframe.setAttribute('allow', 'microphone *'); // future voice support, harmless no-op today

    wrap.appendChild(iframe);
    document.body.appendChild(wrap);
    return wrap;
  }

  var frameWrap;

  function toggleWidget() {
    isOpen = !isOpen;
    if (!frameWrap) frameWrap = createFrame();
    frameWrap.classList.toggle('aisp-open', isOpen);
  }

  function init() {
    injectStyles();
    createBubble();
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init);
  } else {
    init();
  }
})();
